class Solution:
    def maxSatisfied(self, customers, grumpy, minutes):
        n = len(customers)
        base = sum(customers[i] for i in range(n) if grumpy[i] == 0)
        best = 0
        for start in range(0, n - minutes + 1):
            gain = sum(customers[j] for j in range(start, start + minutes) if grumpy[j] == 1)
            if gain > best:
                best = gain
        return base + best

