class Solution:
    def maxSatisfied(self, customers, grumpy, minutes):
        n = len(customers)
        base = sum(customers[i] for i in range(n) if grumpy[i] == 0)
        window = 0
        best = 0
        for i in range(n):
            if grumpy[i] == 1:
                window += customers[i]
            if i >= minutes and grumpy[i - minutes] == 1:
                window -= customers[i - minutes]
            if window > best:
                best = window
        return base + best

